  50% { transform: translateY(-20px); }
}

.animate-fade-in {
  animation: fadeIn 0.6s ease-in-out;
}

.animate-slide-up {
  animation: slideUp 0.8s ease-out;
}

.animate-float {
  animation: float 6s ease-in-out infinite;
}

.glass-effect {
