    transform: scale(1);
    opacity: 1;
  }
}

.animate-fadeInUp {
  animation: fadeInUp 0.6s ease-out forwards;
}

.animate-scaleIn {
  animation: scaleIn 0.4s ease-out forwards;
}

/* Stagger children animations */
.stagger-children > * {
  animation-delay: calc(var(--stagger-delay, 0) * 100ms);
